import{_ as e,o as t,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"40. Telephone Calls To Doctors Outside Of Working Hours","description":"","frontmatter":{"title":"40. Telephone Calls To Doctors Outside Of Working Hours","eba":"Doctors in Training 2022-2026","topics":["hours","on-call","allowances"]},"headers":[],"relativePath":"ebas/doctors-in-training/hours-of-work/40-telephone-calls-to-doctors-outside-of-working-hours.md","filePath":"ebas/doctors-in-training/hours-of-work/40-telephone-calls-to-doctors-outside-of-working-hours.md"}'),a={name:"ebas/doctors-in-training/hours-of-work/40-telephone-calls-to-doctors-outside-of-working-hours.md"};function n(l,o,i,c,h,u){return t(),r("div",null,[...o[0]||(o[0]=[s('<h1 id="_40-telephone-calls-to-doctors-outside-of-working-hours" tabindex="-1">40. Telephone Calls To Doctors Outside Of Working Hours <a class="header-anchor" href="#_40-telephone-calls-to-doctors-outside-of-working-hours" aria-label="Permalink to &quot;40. Telephone Calls To Doctors Outside Of Working Hours&quot;">​</a></h1><p><strong>40.1</strong> The provisions of this clause 40 are to be read in conjunction with <a href="/eba/ebas/doctors-in-training/hours-of-work/38-on-call.html">clause 38</a> (On-call).</p><p><strong>40.2</strong> The Health Service must have mandatory Protocols in operation that govern the use of telephone consultations with Doctors who are on-call. The Protocols must ensure:</p><p><strong>(a)</strong> the number of trivial or unnecessary telephone calls made to Doctors are controlled; and</p><p><strong>(b)</strong> the overall numbers of telephone calls made to Doctors do not increase over time as a result of the changed on-call allowance and particularly in comparison with other health professionals.</p><p><strong>40.3</strong> The Association may review the form and application of the Protocols to ensure their effective operation.</p><p>Plain language terms: after-hours calls.</p>',7)])])}const f=e